/* Uses HostScriptPtrTabRegister from host_script_ptrtab.c */
extern u32 HostScriptPtrTabRegister(const u8 *ptr);

static void pfr_bs_patch_idx(u8 *dst, const void *target) {
    u32 idx = HostScriptPtrTabRegister((const u8 *)target);
    dst[0] = (u8)(idx);
    dst[1] = (u8)(idx >> 8);
    dst[2] = (u8)(idx >> 16);
    dst[3] = (u8)(idx >> 24);
}

